            a: "\u51FA\u8377\u5C65\u6B74\u3068\u73FE\u5730\u306E\u5728\u5EAB\u30ED\u30B0\u3092\u8ABF\u67FB\u3044\u305F\u3057\u307E\u3059\u306E\u3067\u3001\u5916\u7BB1\u306E\u753B\u50CF\u304A\u3088\u3073\u5230\u7740\u6642\u306E\u68B1\u5305\u72B6\u6CC1\u3092\u64AE\u5F71\u3044\u305F\u3060\u304D\u3001\u901F\u3084\u304B\u306B\u62C5\u5F53\u30B9\u30BF\u30C3\u30D5\u307E\u3067\u30C1\u30E3\u30C3\u30C8\u30EF\u30FC\u30AF\u306B\u3066\u3054\u9023\u7D61\u304F\u3060\u3055\u3044\u3002",
            open: false
